# Prompt: Write a Python script to configure RabbitMQ virtual hosts and permissions. Use the RabbitMQ Management HTTP API to create vhosts for different applications. Set up users and grant permissions for queue operations. This is for our multi-tenant message broker setup.
# Category: rabbitmq_vhost_isolation

import requests

# Set up RabbitMQ management API URL
base_url = "http://localhost:15672/"

# Define the virtual hosts and users to create
vhosts = {
    "app1": {"users": ["user1", "user2"]},
    "app2": {"users": ["user3", "user4"]}
}

# Create virtual hosts for each application
for app, data in vhosts.items():
    url = f"{base_url}/api/vhosts/{app}"
    response = requests.put(url)
    if response.status_code != 204:
        print(f"Failed to create virtual host {app}: {response.text}")

# Set up users and grant permissions for queue operations
users = {
    "user1": {"permissions": ["read", "write"]},
    "user2": {"permissions": ["read", "write"]},
    "user3": {"permissions": ["read", "write"]},
    "user4": {"permissions": ["read", "write"]}
}

# Grant permissions for each user
for user, data in users.items():
    url = f"{base_url}/api/users/{user}"
    response = requests.put(url)
    if response.status_code != 204:
        print(f"Failed to grant permissions for {user}: {response.text}")